        die("updatePnotePatient() did not find id '" . text($id) . "'");
    }

    $activity = $assigned_to ? '1' : '0';

    $pid = $row['pid'];

    if ($pid != 0 || (int)$patient_id < 1) {
        (new SystemLogger())->errorLogCaller("invalid operation", ['id' => $id, 'patient_id' => $patient_id, 'pid' => $pid]);
